    const gert::Shape &x_shape = x_storage->GetOriginShape();
    const gert::Shape &w_shape = w_storage->GetOriginShape();

    uint32_t batch = x_shape.GetDim(0);
    uint32_t inFeat = x_shape.GetDim(1);
    uint32_t outFeat = w_shape.GetDim(0);
    uint32_t totalLength = batch * outFeat;

    // gn_gamma size equals outFeat
    const gert::StorageShape *gamma_storage = context->GetInputShape(4);
    uint32_t numGroups = gamma_storage->GetOriginShape().GetDim(0);
    uint32_t groupSize = outFeat / numGroups;

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *epsilon = attrs->GetAttrPointer<float>(0);
    float eps = (epsilon != nullptr) ? *epsilon : 1e-5f;

    uint32_t maxTile = UB_BUDGET_BYTES / 20;
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);
    uint32_t tileLen = maxTile;
    if (totalLength < tileLen) {
        uint32_t aligned = AlignDown(totalLength, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : totalLength;
    }

    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_batchSize(batch);
    tiling.set_numGroups(numGroups);
    tiling.set_outFeatures(outFeat);
    tiling.set_groupSize(groupSize);
    tiling.set_inFeatures(inFeat);
    tiling.set_epsilon(eps);
    tiling.set_invGroupSize(1.0f / groupSize);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());
    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
